#include<bits/stdc++.h>
using namespace std;
int main()
{
	int n,i,s;
	cin>>n;
	vector<int> x(n+5); 
	for(i=0;i<n;i++)
	{
	cin>>x[i];	
	}
	vector<int> y(n+5);
	y[n+1]={0};
	for(i=0;i<n;i++)
	{
		for(s=i-1;s>=0;s--)
		if(x[s]<x[i]) y[i]++;
	}
	for(int i=0;i<n;i++)
	{
		cout<<y[i]<<" ";
	}
	return 0;
}
